script:
if frappe.session.user == "Guest":
    conditions = "1=0"
else:
    # frappe.db.get_value is whitelisted; use it to check the User's roles
    has_student_role = frappe.db.get_value(
        "Has Role",
        {"parent": frappe.session.user, "parenttype": "User", "role": "Student Portal"},
        "name"
    )
    if has_student_role:
        student = frappe.db.get_value(
            "Student",
            {"portal_email": frappe.session.user},
            ["student_class", "section"],
            as_dict=True
        )
        if student:
            if student.section:
                conditions = f"(`student_class` = '{student.student_class}' AND `section` = '{student.section}')"
            else:
                conditions = f"`student_class` = '{student.student_class}'"
        else:
            conditions = "1=0"
    else:
        conditions = ""

# Dynamic Account Selection
if doc.custom_payment_method and not doc.custom_account_paid_to:
    parent_map = {"Bank": "Bank Accounts - SS", "Cash": "Cash In Hand - SS"}
    parent_acc = parent_map.get(doc.custom_payment_method)
    if parent_acc:
        account = frappe.db.get_value("Account", {"parent_account": parent_acc, "is_group": 0}, "name")
        if account:
            doc.custom_account_paid_to = account
        else:
            frappe.msgprint("Warning: No leaf account found under " + parent_acc)

if doc.student_class:
    filters = {'student_class': doc.student_class}
    if doc.get('section'):
        filters['section'] = doc.section
    doc.number_of_students = frappe.db.count('Student', filters)

if doc.student_class:
    filters = {'student_class': doc.student_class}
    if doc.get('section'):
        filters['section'] = doc.section
    students = frappe.get_all('Student', filters=filters, fields=['name', 'full_name', 'student_class', 'section', 'house', 'date_of_admission'])
    doc.set('students', [])
    for s in students:
        doc.append('students', {
            'student_reg_no': s.name,
            'full_name': s.full_name,
            'student_class': s.student_class,
            'section': s.section,
            'house': s.house,
            'date_of_admission': s.date_of_admission,
        })

if doc.from_class:
    filters = {'student_class': doc.from_class}
    if doc.get('from_section'):
        filters['section'] = doc.from_section
    students = frappe.get_all('Student', filters=filters, fields=['name', 'full_name', 'student_class', 'section'])
    doc.set('students', [])
    for s in students:
        doc.append('students', {
            'student_reg_no': s.name,
            'full_name': s.full_name,
            'current_class': s.student_class,
            'current_section': s.section,
            'status': 'Promote',
        })
    doc.number_of_students = len(students)

promoted = 0
skipped = 0

for item in doc.students:
    if item.status == 'Promote':
        frappe.db.set_value('Student', item.student_reg_no, {
            'student_class': doc.to_class,
            'section': doc.to_section if doc.to_section else item.current_section,
        })
        promoted += 1
    else:
        skipped += 1

frappe.msgprint(f'Successfully promoted {promoted} students to {doc.to_class}. Skipped: {skipped}.')

if doc.student_class:
    filters = {'student_class': doc.student_class}
    if doc.get('section'):
        filters['section'] = doc.section
    doc.number_of_students = frappe.db.count('Student', filters)

# Fetch Student Attendance
student_filters = {}
if doc.get('filter_date_from'):
    student_filters['date'] = ['>=', doc.filter_date_from]
if doc.get('filter_date_to'):
    student_filters['date'] = ['<=', doc.filter_date_to]
if doc.get('filter_class'):
    student_filters['student_class'] = doc.filter_class
if doc.get('filter_section'):
    student_filters['section'] = doc.filter_section

student_attendance = frappe.get_all('Student Attendance',
    filters=student_filters,
    fields=['student_name', 'admission_no', 'date', 'check_in_time', 'check_out_time', 'status', 'attendance'],
    order_by='date desc',
    limit=100
)

student_rows = ""
for a in student_attendance:
    student_rows += "<tr><td>" + str(a.admission_no or '') + "</td><td>" + str(a.student_name or '') + "</td><td>" + str(a.date or '') + "</td><td>" + str(a.check_in_time or '') + "</td><td>" + str(a.check_out_time or '') + "</td><td>" + str(a.status or '') + "</td><td>" + str(a.attendance or '') + "</td></tr>"

doc.student_attendance_html = "<table class='table table-bordered table-sm'><thead class='thead-dark'><tr><th>Admission No</th><th>Student Name</th><th>Date</th><th>Check In</th><th>Check Out</th><th>Status</th><th>Attendance</th></tr></thead><tbody>" + student_rows + "</tbody></table>" if student_rows else "<p>No student attendance records found.</p>"

staff_attendance = frappe.get_all('Staff Attendance',
    fields=['staff_name', 'staff_id', 'date', 'check_in_time', 'check_out_time', 'status', 'attendance'],
    order_by='date desc',
    limit=100
)

staff_rows = ""
for a in staff_attendance:
    staff_rows += "<tr><td>" + str(a.staff_id or '') + "</td><td>" + str(a.staff_name or '') + "</td><td>" + str(a.date or '') + "</td><td>" + str(a.check_in_time or '') + "</td><td>" + str(a.check_out_time or '') + "</td><td>" + str(a.status or '') + "</td><td>" + str(a.attendance or '') + "</td></tr>"

doc.staff_attendance_html = "<table class='table table-bordered table-sm'><thead class='thead-dark'><tr><th>Staff ID</th><th>Staff Name</th><th>Date</th><th>Check In</th><th>Check Out</th><th>Status</th><th>Attendance</th></tr></thead><tbody>" + staff_rows + "</tbody></table>" if staff_rows else "<p>No staff attendance records found.</p>"

existing = frappe.db.exists("Class Result", {"source_doc": doc.name})
if not existing and doc.student_class and doc.test_items:
    cr = frappe.get_doc({
        "doctype": "Class Result",
        "source_doc": doc.name,
        "student_class": doc.student_class,
        "subject": doc.subject,
        "date": doc.date,
        "total_students": doc.number_of_students
    })
    for item in doc.test_items:
        cr.append("scores", {
            "student_admission_no": item.student_admission_no,
            "student_full_name": item.student_full_name,
            "marks_obtained": item.marks_obtained,
            "percentage": item.percentage,
            "status": item.status,
            "grade": item.grade
        })
    cr.insert(ignore_permissions=True)

if doc.has_opening_balance and doc.opening_balance and doc.opening_balance_date:
    if not doc.is_new():
        existing = frappe.db.exists("Journal Entry", {
            "user_remark": "Opening Balance - " + doc.name,
            "docstatus": ["!=", 2]
        })
        if not existing:
            debit_account = frappe.db.get_single_value("School Settings1", "debit_account")
            credit_account = frappe.db.get_single_value("School Settings1", "credit_account")
            if debit_account and credit_account:
                company = frappe.db.get_single_value("Global Defaults", "default_company")
                cost_center = doc.cost_center if doc.cost_center else None
                je = frappe.get_doc({
                    "doctype": "Journal Entry",
                    "voucher_type": "Opening Entry",
                    "posting_date": doc.opening_balance_date,
                    "company": company,
                    "user_remark": "Opening Balance - " + doc.name,
                    "accounts": [
                        {
                            "account": debit_account,
                            "party_type": "Customer",
                            "party": doc.full_name,
                            "debit_in_account_currency": doc.opening_balance,
                            "debit": doc.opening_balance,
                            "credit_in_account_currency": 0,
                            "credit": 0,
                            "cost_center": cost_center
                        },
                        {
                            "account": credit_account,
                            "debit_in_account_currency": 0,
                            "debit": 0,
                            "credit_in_account_currency": doc.opening_balance,
                            "credit": doc.opening_balance,
                            "cost_center": cost_center
                        }
                    ]
                })
                je.insert(ignore_permissions=True)
                je.submit()
                frappe.msgprint("Opening Balance Journal Entry created: " + je.name)
            else:
                frappe.throw("Please set Debit and Credit accounts in School Settings1 first.")

